INSERT INTO shell_messages (message_id, from_shell_id, to_shell_id, body, created_at, read_at, kind, dedupe_key) VALUES (428, 6, 9, 'SPRINT 25 seq 9 UNIT REPORT (task #85) — SHIPPED.

